def solve(n: int, k: int) -> int:
    if k == 0:
        return 1 if n >= 1 else 0

    from functools import lru_cache

    s = bin(n)[2:]
    m = len(s)

    @lru_cache(maxsize=None)
    def dp(pos, cnt, tight):
        if pos == m:
            return 1 if cnt == 0 else 0
        limit = int(s[pos]) if tight else 1
        res = 0
        for bit in range(0, limit + 1):
            new_tight = tight and (bit == limit)
            new_cnt = cnt - (bit == 1)
            if new_cnt >= 0:
                res += dp(pos + 1, new_cnt, new_tight)
        return res

    total = dp(0, k, True)

    for length in range(1, m):
        @lru_cache(maxsize=None)
        def dp2(pos, cnt):
            if pos == length:
                return 1 if cnt == 0 else 0
            res = 0
            for bit in range(0, 2):
                new_cnt = cnt - (bit == 1)
                if new_cnt >= 0:
                    res += dp2(pos + 1, new_cnt)
            return res
        total += dp2(1, k - 1)  # first bit must be 1

    return total
